#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,m,k;
int a[N];
int main(){
    scanf("%d",&m);
    k=1;
    while(m>=k)
        m-=k,a[++n]=k,k*=2;
    if(m)
        a[++n]=m;
    sort(a+1,a+n+1);
    printf("%d\n",n);
    for(int i=1;i<=n;i++){
        if(a[i]==a[i+1] && i<n && a[i]!=1)
            a[i]--,a[i+1]++;
        printf("%d ",a[i]);
    }
    return 0;
}
